import threading
from exchange_service import ThreadSafeMatchingEngine
from models import Side

# Stress: concurrent snapshot() readers while writers match on the SAME symbol.
# snapshot is NOT under the lock and _peek_active mutates the heap. Look for crash/inconsistency.
errors = []
for trial in range(50):
    e = ThreadSafeMatchingEngine(['AAPL'])
    # seed many resting orders that will be cancelled to create dead tops
    for i in range(200):
        e.submit_order('AAPL', Side.SELL, price_cents=1000+i, quantity=1)
    # cancel half to create dead heap tops that _peek_active will pop
    for i in range(1, 100):
        try: e.cancel_order(f'ord-{i}')
        except Exception: pass

    stop = threading.Event()
    def reader():
        while not stop.is_set():
            try:
                e.snapshot('AAPL')
            except Exception as ex:
                errors.append(('reader', type(ex).__name__, str(ex)))
                return
    def writer():
        for j in range(50):
            try:
                e.submit_order('AAPL', Side.BUY, price_cents=2000, quantity=1)
            except Exception as ex:
                errors.append(('writer', type(ex).__name__, str(ex)))
                return
    rs = [threading.Thread(target=reader) for _ in range(8)]
    ws = [threading.Thread(target=writer) for _ in range(4)]
    for t in rs+ws: t.start()
    for t in ws: t.join()
    stop.set()
    for t in rs: t.join()
print('errors:', len(errors))
for er in errors[:10]: print(er)
